  if (state.status === 'error') {
    return (
      <Alert
        type="error"
        showIcon
        title="Failed to load /api/v1/me"
        description={state.error}
        style={{ margin: 24 }}
      />
    );
  }
  return (
    <Card title="Authenticated as">
